import NextAuth from "next-auth"
import Credentials from "next-auth/providers/credentials"
import { MongoDBAdapter } from "@auth/mongodb-adapter"
import { connectToDatabase } from "@/../../infra/db/mongodb"
import bcrypt from "bcryptjs"
import { authConfig } from "./auth.config"

export const { handlers, auth, signIn, signOut } = NextAuth({
    ...authConfig,
    adapter: MongoDBAdapter(connectToDatabase().then(res => res.client as any)),
    providers: [
        Credentials({
            async authorize(credentials) {
                if (!credentials?.email || !credentials?.password) return null

                const db = await (await connectToDatabase()).db
                const user = await db.collection("users").findOne({ email: credentials.email })

                if (!user || !user.password) {
                    console.error("User not found or password missing")
                    return null
                }

                const isValid = await bcrypt.compare(credentials.password as string, user.password)

                if (!isValid) {
                    console.error("Invalid password")
                    return null
                }

                return {
                    id: user._id.toString(),
                    email: user.email,
                    name: user.name || user.email.split("@")[0]
                }
            }
        })
    ],
    callbacks: {
        ...authConfig.callbacks,
        async signIn({ user, account, profile }) {
            if (account?.provider === "google") {
                const db = await (await connectToDatabase()).db
                const existingUser = await db.collection("users").findOne({ email: user.email })

                if (existingUser) {
                    // Update auth_providers if google is not present
                    const providers = existingUser.auth_providers || ["email"]
                    if (!providers.includes("google")) {
                        await db.collection("users").updateOne(
                            { _id: existingUser._id },
                            { $set: { auth_providers: [...providers, "google"] } }
                        )
                    }
                }
            }
            return true
        }
    },
    events: {
        async createUser({ user }) {
            const db = await (await connectToDatabase()).db
            await db.collection("users").updateOne(
                { _id: (user as any).id },
                {
                    $set: {
                        auth_providers: ["google"],
                        created_at: new Date().toISOString(),
                        updated_at: new Date().toISOString()
                    }
                }
            )
        }
    }
})
